LOGO_B64 = ""
LOGO_HTML = f'<img src="data:image/png;base64," style="max-width:200px;width:100%">'

SUPABASE_URL = "https://lmcefcmjatnixrsggyvz.supabase.co"
SUPABASE_KEY = st.secrets["SUPABASE_KEY"]
ANTHROPIC_KEY = st.secrets.get("ANTHROPIC_KEY", "")

HDR = {"apikey": SUPABASE_KEY, "Authorization": f"Bearer {SUPABASE_KEY}",
       "Content-Type": "application/json", "Prefer": "return=representation"}

def sb_get(t, p=""):
    try:
        r = requests.get(f"{SUPABASE_URL}/rest/v1/{t}?{p}", headers=HDR, timeout=10)
        return r.json() if r.ok else []
    except: return []

def sb_post(t, d, upsert=False):
    h = {**HDR, "Prefer": "resolution=merge-duplicates,return=representation" if upsert else "return=representation"}
    try:
        r = requests.post(f"{SUPABASE_URL}/rest/v1/{t}", json=d, headers=h, timeout=10)
        return r.ok
    except: return False

def sb_patch(t, f, d):
    try:
        r = requests.patch(f"{SUPABASE_URL}/rest/v1/{t}?{f}", json=d, headers=HDR, timeout=10)
        return r.ok
    except: return False

def sb_delete(t, f):
    try:
        r = requests.delete(f"{SUPABASE_URL}/rest/v1/{t}?{f}", headers={**HDR, "Prefer": ""}, timeout=10)
        return r.ok
    except: return False

def ler_contrato_ia(img_bytes, media_type="image/jpeg"):
    if not ANTHROPIC_KEY:
        return None, "Chave Anthropic não configurada nos Secrets"
    b64 = base64.b64encode(img_bytes).decode("utf-8")
    prompt = """Analise o contrato de transporte e retorne APENAS JSON puro sem markdown:
{"cliente":"AUTOPORT ou SADA ou VIX etc","motorista":"NOME EM MAIUSCULAS","placa":"ABC1234","frota":"","contrato":"numero","data":"DD/MM/AAAA","fat_bruto":0.0,"chapa":0.0,"destino":"Cidade/UF","qtd_veiculos":0,"dt_pagamento":"DD/MM/AAAA ou vazio"}"""
    is_pdf = media_type == "application/pdf"
    hdrs = {"x-api-key": ANTHROPIC_KEY, "anthropic-version": "2023-06-01", "content-type": "application/json"}
    if is_pdf: hdrs["anthropic-beta"] = "pdfs-2024-09-25"
    bloco = {"type": "document" if is_pdf else "image", "source": {"type": "base64", "media_type": media_type, "data": b64}}
    try:
        r = requests.post("https://api.anthropic.com/v1/messages", headers=hdrs,
            json={"model": "claude-sonnet-4-20250514", "max_tokens": 1000,
                  "messages": [{"role": "user", "content": [bloco, {"type": "text", "text": prompt}]}]}, timeout=30)
        if not r.ok: return None, f"Erro API: {r.status_code}"
        texto = r.json()["content"][0]["text"]
        clean = texto.replace("```json", "").replace("```", "").strip()
        s = clean.find("{"); e = clean.rfind("}") + 1
        if s >= 0 and e > s: return json.loads(clean[s:e]), None
        return None, "JSON não encontrado"
    except Exception as ex: return None, str(ex)

